import math
import time
import random

class GPSSpoofJump:
    """Instantly shift reported GPS position."""

    def __init__(self, offset_north_m=500.0, offset_east_m=0.0, offset_alt_m=0.0):
        self.offset_n = offset_north_m
        self.offset_e = offset_east_m
        self.offset_alt = offset_alt_m
        self.active = False

    def start(self):
        self.active = True
        dist = math.sqrt(self.offset_n**2 + self.offset_e**2)
        print(f'[*] GPS Jump Spoof active — {dist:.0f}m displacement')

    def apply_to_position(self, lat, lon, alt):
        if not self.active:
            return (lat, lon, alt)
