#!/usr/bin/env python3
"""GPS Clock Jump Detector — detects spoofing via receiver clock anomalies."""
import time
import collections

class ClockJumpDetector:
    WINDOW = 30  # samples
    THRESHOLD_NS = 50  # nanoseconds

    def __init__(self, threshold_ns=None):
        if threshold_ns:
            self.THRESHOLD_NS = threshold_ns
        self.history = collections.deque(maxlen=self.WINDOW)
        self.prev_bias = None
        self.prev_time = None

    def update(self, clock_bias_s, timestamp=None):
        t = timestamp or time.time()
        result = {'spoofing': False, 'rate_ns': 0.0}
        if self.prev_bias is not None:
            dt = t - self.prev_time
            if dt > 0:
                rate = abs(clock_bias_s - self.prev_bias) / dt
                rate_ns = rate * 1e9
                self.history.append(rate_ns)
                result['rate_ns'] = rate_ns
                if rate_ns > self.THRESHOLD_NS:
                    result['spoofing'] = True
                    result['confidence'] = min(1.0, rate_ns / (self.THRESHOLD_NS * 3))
        self.prev_bias = clock_bias_s
        self.prev_time = t
        return result

