#!/usr/bin/env python3
"""Anti-Jam Frequency Hopping — pseudorandom channel switching."""
import hashlib
import struct
import time

class FrequencyHopper:
    def __init__(self, freq_min=969e6, freq_max=1206e6, n_channels=51, hop_rate=76900, key=b'default'):
        self.freq_min = freq_min
        self.freq_max = freq_max
        self.n_channels = n_channels
        self.hop_rate = hop_rate  # hops per second
        self.key = key
        self.channel_spacing = (freq_max - freq_min) / n_channels

    def get_frequency(self, hop_number):
        """Deterministic frequency for hop number (shared secret key)."""
        h = hashlib.sha256(self.key + struct.pack('>Q', hop_number)).digest()
        idx = int.from_bytes(h[:2], 'big') % self.n_channels
        return self.freq_min + idx * self.channel_spacing

    def get_current_hop(self):
        t = time.time()
        return int(t * self.hop_rate)

    def get_current_frequency(self):
        return self.get_frequency(self.get_current_hop())

    def generate_sequence(self, n_hops=100, start_hop=0):
        return [self.get_frequency(start_hop + i) for i in range(n_hops)]

