"""Counter-UAS RF Jammer — disrupts drone control and navigation links."""
import time
import math
import threading
import random

class CounterUASJammer:
    """Multi-band jammer targeting common drone control frequencies."""

    BANDS = {
        'wifi_2g': (2400e6, 2500e6),    # WiFi 2.4 GHz (DJI, etc)
        'wifi_5g': (5725e6, 5875e6),    # WiFi 5.8 GHz
        'gps_l1':  (1565e6, 1585e6),    # GPS L1
        'gps_l2':  (1217e6, 1237e6),    # GPS L2
        'ism_900': (902e6, 928e6),       # ISM 900 MHz
    }

    def __init__(self, power_dbm=33, bands=None):
        self.power_dbm = power_dbm
        self.active_bands = bands or ['wifi_2g', 'wifi_5g', 'gps_l1']
        self.active = False
        self._thread = None

    def effective_range_m(self, band_name, target_sensitivity_dbm=-90):
        freq = sum(self.BANDS[band_name]) / 2
        c = 299792458
        delta = self.power_dbm - target_sensitivity_dbm
        fspl_const = 20 * math.log10(freq) + 20 * math.log10(4 * math.pi / c)
        return 10 ** ((delta - fspl_const) / 20)

    def start(self, duration=None):
        self.active = True
        for band in self.active_bands:
            r = self.effective_range_m(band)
            f = sum(self.BANDS[band]) / 2 / 1e6
            print(f'  [{band}] {f:.0f} MHz — range {r:.0f}m')
        print(f'[*] C-UAS Jammer active ({len(self.active_bands)} bands, {self.power_dbm} dBm)')
        if duration:
            def _stop():
                time.sleep(duration)
                self.stop()
            self._thread = threading.Thread(target=_stop, daemon=True)
            self._thread.start()

    def stop(self):
        self.active = False
        print('[*] C-UAS Jammer stopped')

    def status(self):
        return {'active': self.active, 'bands': self.active_bands, 'power_dbm': self.power_dbm}

