"""Russian EW Barrage Jammer — broadband noise jamming simulation."""
import math
import time
import random

class BarrageJammer:
    """Models broadband barrage jamming like Pole-21 / R-330Zh Zhitel."""

    SYSTEMS = {
        'Pole-21': {'freq_range': (1.0e9, 2.0e9), 'power_w': 100, 'range_km': 25},
        'R-330Zh': {'freq_range': (1.0e9, 2.0e9), 'power_w': 50, 'range_km': 15},
        'Murmansk-BN': {'freq_range': (1.5e6, 30e6), 'power_w': 5000, 'range_km': 5000},
        'Krasukha-2': {'freq_range': (8.0e9, 12.0e9), 'power_w': 1000, 'range_km': 250},
    }

    def __init__(self, system='Pole-21'):
        if system in self.SYSTEMS:
            cfg = self.SYSTEMS[system]
            self.freq_min, self.freq_max = cfg['freq_range']
            self.power_w = cfg['power_w']
            self.max_range_km = cfg['range_km']
        else:
            self.freq_min, self.freq_max = 1e9, 2e9
            self.power_w = 100
            self.max_range_km = 25
        self.system_name = system
        self.active = False

    def power_dbm(self):
        return 10 * math.log10(self.power_w * 1000)

    def jamming_power_at_distance(self, distance_km):
        """Power spectral density at distance (simplified)."""
        if distance_km <= 0:
            return self.power_dbm()
        freq_center = (self.freq_min + self.freq_max) / 2
        c = 299792458
        fspl = 20 * math.log10(distance_km * 1000) + 20 * math.log10(freq_center) + 20 * math.log10(4 * math.pi / c)
        return self.power_dbm() - fspl

    def is_effective(self, distance_km, target_sensitivity_dbm=-130):
        return self.jamming_power_at_distance(distance_km) > target_sensitivity_dbm

    def activate(self):
        self.active = True
        bw = (self.freq_max - self.freq_min) / 1e6
        print(f'[*] {self.system_name} active — {bw:.0f} MHz bandwidth, {self.power_w}W, range {self.max_range_km}km')

    def deactivate(self):
        self.active = False
